    }

    [TestMethod]
    public void GetStockLevel_AfterAddStock_ReturnsCorrectQuantity()
    {
        _tracker.AddStock("SKU-1", 50);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-1"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_NullSku_Throws()
    {
        _tracker.GetStockLevel(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_EmptySku_Throws()
    {
        _tracker.GetStockLevel("");
    }

    #endregion

    #region AddStock Tests

    [TestMethod]
    public void AddStock_NewSku_SetsLevel()
    {
        _tracker.AddStock("SKU-A", 25);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void AddStock_ExistingSku_AccumulatesQuantity()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.AddStock("SKU-A", 15);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddStock_ZeroQuantity_Throws()
    {
        _tracker.AddStock("SKU-A", 0);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddStock_NegativeQuantity_Throws()
    {
        _tracker.AddStock("SKU-A", -5);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddStock_NullSku_Throws()
    {
        _tracker.AddStock(null!, 10);
    }

    #endregion

    #region RemoveStock Tests

    [TestMethod]
    public void RemoveStock_SufficientStock_ReducesLevel()
    {
        _tracker.AddStock("SKU-B", 100);
        _tracker.RemoveStock("SKU-B", 30);
        Assert.AreEqual(70, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    public void RemoveStock_EntireStock_LeavesZero()
    {
        _tracker.AddStock("SKU-B", 50);
        _tracker.RemoveStock("SKU-B", 50);
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
