    }

    [TestMethod]
    public void NeedsReorder_StockAtDefaultThreshold_ReturnsTrue()
    {
        _tracker.AddStock("SKU-C", 10);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-C"));
    }

    [TestMethod]
