+using Warehouse;
+
+namespace Tests;
+
+[TestClass]
+public class InventoryTrackerTests
+{
+    private InventoryTracker _tracker = null!;
+
+    [TestInitialize]
+    public void Setup()
+    {
+        _tracker = new InventoryTracker("MainWarehouse");
+    }
+
+    #region Constructor Tests
+
+    [TestMethod]
+    public void Constructor_WithValidName_SetsWarehouseName()
+    {
+        var tracker = new InventoryTracker("East");
+        Assert.AreEqual("East", tracker.WarehouseName);
+    }
+
+    [TestMethod]
+    public void Constructor_DefaultName_UsesDefault()
+    {
+        var tracker = new InventoryTracker();
+        Assert.AreEqual("Default", tracker.WarehouseName);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentException))]
+    public void Constructor_NullName_Throws()
+    {
+        _ = new InventoryTracker(null!);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentException))]
+    public void Constructor_WhitespaceName_Throws()
+    {
+        _ = new InventoryTracker("   ");
+    }
+
+    #endregion
+
+    #region GetStockLevel Tests
+
+    [TestMethod]
+    public void GetStockLevel_UnknownSku_ReturnsZero()
+    {
+        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-999"));
+    }
+
+    [TestMethod]
+    public void GetStockLevel_AfterAddStock_ReturnsCorrectQuantity()
+    {
+        _tracker.AddStock("SKU-1", 50);
