+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentException))]
+    public void GetStockLevel_NullSku_Throws()
+    {
+        _tracker.GetStockLevel(null!);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentException))]
+    public void GetStockLevel_EmptySku_Throws()
+    {
+        _tracker.GetStockLevel("");
+    }
+
+    #endregion
+
+    #region AddStock Tests
+
+    [TestMethod]
+    public void AddStock_NewSku_SetsLevel()
+    {
+        _tracker.AddStock("SKU-A", 25);
+        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
+    }
+
+    [TestMethod]
+    public void AddStock_ExistingSku_AccumulatesQuantity()
+    {
+        _tracker.AddStock("SKU-A", 10);
+        _tracker.AddStock("SKU-A", 15);
+        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentOutOfRangeException))]
+    public void AddStock_ZeroQuantity_Throws()
+    {
+        _tracker.AddStock("SKU-A", 0);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentOutOfRangeException))]
+    public void AddStock_NegativeQuantity_Throws()
+    {
+        _tracker.AddStock("SKU-A", -5);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentException))]
+    public void AddStock_NullSku_Throws()
+    {
+        _tracker.AddStock(null!, 10);
+    }
+
+    #endregion
+
+    #region RemoveStock Tests
+
+    [TestMethod]
+    public void RemoveStock_SufficientStock_ReducesLevel()
+    {
+        _tracker.AddStock("SKU-B", 100);
+        _tracker.RemoveStock("SKU-B", 30);
+        Assert.AreEqual(70, _tracker.GetStockLevel("SKU-B"));
+    }
+
+    [TestMethod]
+    public void RemoveStock_EntireStock_LeavesZero()
+    {
+        _tracker.AddStock("SKU-B", 50);
+        _tracker.RemoveStock("SKU-B", 50);
+        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-B"));
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(InvalidOperationException))]
+    public void RemoveStock_ExceedsAvailable_Throws()
+    {
+        _tracker.AddStock("SKU-B", 10);
+        _tracker.RemoveStock("SKU-B", 20);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(InvalidOperationException))]
+    public void RemoveStock_NoStockExists_Throws()
+    {
+        _tracker.RemoveStock("SKU-NONE", 1);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentOutOfRangeException))]
+    public void RemoveStock_ZeroQuantity_Throws()
+    {
+        _tracker.AddStock("SKU-B", 10);
+        _tracker.RemoveStock("SKU-B", 0);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentOutOfRangeException))]
+    public void RemoveStock_NegativeQuantity_Throws()
+    {
+        _tracker.RemoveStock("SKU-B", -1);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentException))]
+    public void RemoveStock_NullSku_Throws()
+    {
+        _tracker.RemoveStock(null!, 5);
+    }
+
+    #endregion
+
+    #region Reorder Threshold Tests
+
+    [TestMethod]
+    public void NeedsReorder_StockBelowDefaultThreshold_ReturnsTrue()
+    {
+        _tracker.AddStock("SKU-C", 5);
+        Assert.IsTrue(_tracker.NeedsReorder("SKU-C"));
+    }
+
+    [TestMethod]
+    public void NeedsReorder_StockAtDefaultThreshold_ReturnsTrue()
+    {
+        _tracker.AddStock("SKU-C", 10);
+        Assert.IsTrue(_tracker.NeedsReorder("SKU-C"));
+    }
+
+    [TestMethod]
+    public void NeedsReorder_StockAboveDefaultThreshold_ReturnsFalse()
+    {
+        _tracker.AddStock("SKU-C", 11);
+        Assert.IsFalse(_tracker.NeedsReorder("SKU-C"));
+    }
+
+    [TestMethod]
+    public void NeedsReorder_NoStock_ReturnsTrue()
+    {
+        Assert.IsTrue(_tracker.NeedsReorder("SKU-NEW"));
+    }
+
+    [TestMethod]
+    public void SetReorderThreshold_CustomThreshold_IsRespected()
+    {
+        _tracker.SetReorderThreshold("SKU-D", 50);
+        _tracker.AddStock("SKU-D", 40);
+        Assert.IsTrue(_tracker.NeedsReorder("SKU-D"));
+    }
+
+    [TestMethod]
+    public void SetReorderThreshold_StockAboveCustom_ReturnsFalse()
+    {
+        _tracker.SetReorderThreshold("SKU-D", 20);
+        _tracker.AddStock("SKU-D", 100);
+        Assert.IsFalse(_tracker.NeedsReorder("SKU-D"));
+    }
+
+    [TestMethod]
+    public void SetReorderThreshold_ZeroThreshold_OnlyReordersWhenEmpty()
+    {
+        _tracker.SetReorderThreshold("SKU-E", 0);
+        _tracker.AddStock("SKU-E", 0); // won't add (throws), so stock stays 0
+        Assert.IsTrue(_tracker.NeedsReorder("SKU-E"));
+    }
+
+    [TestMethod]
+    public void GetReorderThreshold_NoCustomSet_ReturnsDefault()
+    {
+        Assert.AreEqual(10, _tracker.GetReorderThreshold("SKU-X"));
+    }
+
+    [TestMethod]
+    public void GetReorderThreshold_CustomSet_ReturnsCustom()
+    {
+        _tracker.SetReorderThreshold("SKU-X", 42);
+        Assert.AreEqual(42, _tracker.GetReorderThreshold("SKU-X"));
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentOutOfRangeException))]
+    public void SetReorderThreshold_NegativeThreshold_Throws()
+    {
+        _tracker.SetReorderThreshold("SKU-E", -1);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentException))]
+    public void NeedsReorder_NullSku_Throws()
+    {
+        _tracker.NeedsReorder(null!);
+    }
+
+    #endregion
+
+    #region TransferTo Tests
+
+    [TestMethod]
+    public void TransferTo_ValidTransfer_MovesStock()
+    {
+        var destination = new InventoryTracker("Satellite");
+        _tracker.AddStock("SKU-T", 100);
+
+        _tracker.TransferTo(destination, "SKU-T", 40);
+
+        Assert.AreEqual(60, _tracker.GetStockLevel("SKU-T"));
+        Assert.AreEqual(40, destination.GetStockLevel("SKU-T"));
+    }
+
+    [TestMethod]
+    public void TransferTo_EntireStock_SourceBecomesZero()
+    {
+        var destination = new InventoryTracker("Overflow");
+        _tracker.AddStock("SKU-T", 75);
+
+        _tracker.TransferTo(destination, "SKU-T", 75);
+
+        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-T"));
+        Assert.AreEqual(75, destination.GetStockLevel("SKU-T"));
+    }
+
+    [TestMethod]
+    public void TransferTo_DestinationAlreadyHasStock_Accumulates()
+    {
+        var destination = new InventoryTracker("Overflow");
+        destination.AddStock("SKU-T", 20);
+        _tracker.AddStock("SKU-T", 50);
+
+        _tracker.TransferTo(destination, "SKU-T", 30);
+
+        Assert.AreEqual(20, _tracker.GetStockLevel("SKU-T"));
+        Assert.AreEqual(50, destination.GetStockLevel("SKU-T"));
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(InvalidOperationException))]
+    public void TransferTo_InsufficientStock_Throws()
+    {
+        var destination = new InventoryTracker("Satellite");
+        _tracker.AddStock("SKU-T", 10);
+
+        _tracker.TransferTo(destination, "SKU-T", 20);
+    }
+
+    [TestMethod]
+    public void TransferTo_InsufficientStock_NoPartialTransfer()
+    {
+        var destination = new InventoryTracker("Satellite");
+        _tracker.AddStock("SKU-T", 10);
+
+        try { _tracker.TransferTo(destination, "SKU-T", 20); }
+        catch (InvalidOperationException) { }
+
+        // Source unchanged, destination unchanged
+        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-T"));
+        Assert.AreEqual(0, destination.GetStockLevel("SKU-T"));
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(InvalidOperationException))]
+    public void TransferTo_SameWarehouse_Throws()
+    {
+        _tracker.AddStock("SKU-T", 50);
+        _tracker.TransferTo(_tracker, "SKU-T", 10);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentNullException))]
+    public void TransferTo_NullDestination_Throws()
+    {
+        _tracker.AddStock("SKU-T", 50);
+        _tracker.TransferTo(null!, "SKU-T", 10);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentOutOfRangeException))]
+    public void TransferTo_ZeroQuantity_Throws()
+    {
+        var destination = new InventoryTracker("Satellite");
+        _tracker.AddStock("SKU-T", 50);
+        _tracker.TransferTo(destination, "SKU-T", 0);
+    }
+
+    [TestMethod]
+    [ExpectedException(typeof(ArgumentException))]
+    public void TransferTo_NullSku_Throws()
+    {
+        var destination = new InventoryTracker("Satellite");
+        _tracker.TransferTo(destination, null!, 10);
+    }
+
+    #endregion
+
+    #region Integration / Multi-SKU Tests
+
+    [TestMethod]
+    public void MultipleSkus_IndependentTracking()
+    {
+        _tracker.AddStock("WIDGET", 100);
+        _tracker.AddStock("GADGET", 200);
+        _tracker.RemoveStock("WIDGET", 25);
+
+        Assert.AreEqual(75, _tracker.GetStockLevel("WIDGET"));
+        Assert.AreEqual(200, _tracker.GetStockLevel("GADGET"));
+    }
+
+    [TestMethod]
+    public void TransferTriggersReorder_WhenStockDropsBelowThreshold()
+    {
+        var destination = new InventoryTracker("Satellite");
+        _tracker.SetReorderThreshold("SKU-R", 20);
+        _tracker.AddStock("SKU-R", 50);
+
+        Assert.IsFalse(_tracker.NeedsReorder("SKU-R"));
+
+        _tracker.TransferTo(destination, "SKU-R", 35);
+
+        Assert.IsTrue(_tracker.NeedsReorder("SKU-R"));
+    }
+
+    #endregion
+}
